module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);

    reg [7:0] sum_tmp1, sum_tmp2;
    wire [7:0] mul_a_ext, mul_b_ext;
    wire [7:0] partial_product[size-1:0];
    wire [7:0] add_reg[size-1:0];
    wire [7:0] final_sum;
    genvar i, j;
    assign mul_a_ext = { {(size){1'b0}}, mul_a };
    assign mul_b_ext = { {(size){1'b0}}, mul_b };
    generate
        for(i = 0; i < size; i=i+1) begin
            assign partial_product[i] = mul_b_ext[i] ? (mul_a_ext << i) : 'd0;
        end
    endgenerate

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            sum_tmp1 <= 0;
            sum_tmp2 <= 0;
        end
        else begin
            sum_tmp1 <= (mul_b[0] ? mul_a : 0) + (mul_b[1] ? mul_a << 1 : 0);
            sum_tmp2 <= (mul_b[2] ? mul_a << 2 : 0) + (mul_b[3] ? mul_a << 3 : 0);
        end
    end
    assign mul_out = rst_n ? sum_tmp1 + sum_tmp2 : 0;
endmodule
